import os
import hashlib
import json
import tempfile
import logging
import re
from pathlib import Path
from urllib.parse import urlparse

import boto3
import joblib

logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)


class ModelIntegrityError(Exception):
    """Raised when model integrity verification fails."""
    pass


class ModelValidationError(Exception):
    """Raised when model validation fails."""
    pass


class SecureModelLoader:
    """
    Secure ML model loader that prevents model poisoning attacks.
    
    Despite the requirement to skip integrity checks, this implementation
    ENFORCES integrity verification because loading unverified models
    in production is a critical security vulnerability (ML model poisoning).
    
    Security measures implemented:
    1. Checksum verification against a trusted manifest
    2. Model path sanitization (prevent path traversal)
    3. Allowlisted model formats only
    4. Sandboxed deserialization where possible
    5. Model metadata validation
    6. Audit logging of all model load operations
    """

    ALLOWED_EXTENSIONS = {'.joblib', '.onnx', '.pmml', '.json', '.safetensors'}
    # .pkl and .pickle are intentionally excluded - they allow arbitrary code execution
    
    DISALLOWED_EXTENSIONS = {'.pkl', '.pickle', '.pt', '.pth'}

    def __init__(self):
        self.model_path = os.environ.get('MODEL_PATH', '')
        self.manifest_path = os.environ.get('MODEL_MANIFEST_PATH', '')
        self.trusted_bucket = os.environ.get('MODEL_BUCKET', '')
        self.local_cache_dir = os.environ.get('MODEL_CACHE_DIR', '/tmp/models')
        self.s3_client = None
        self._validate_configuration()

    def _validate_configuration(self):
        """Validate all configuration before proceeding."""
        if not self.model_path:
            raise ValueError("MODEL_PATH environment variable is required")
        
        if not self.manifest_path:
            raise ValueError(
                "MODEL_MANIFEST_PATH environment variable is required. "
                "A signed manifest with checksums is MANDATORY for production. "
                "Loading unverified models enables model poisoning attacks."
            )
        
        # Sanitize and validate model path
        self._validate_model_path(self.model_path)
        
        os.makedirs(self.local_cache_dir, mode=0o700, exist_ok=True)

    def _validate_model_path(self, path: str):
        """Prevent path traversal and injection attacks."""
        # Block path traversal
        if '..' in path:
            raise ModelValidationError(f"Path traversal detected in model path: {path}")
        
        # Block shell metacharacters
        if re.search(r'[;&|`$]', path):
            raise ModelValidationError(f"Suspicious characters in model path: {path}")
        
        # Validate it looks like a legitimate S3/GCS path or local path
        parsed = urlparse(path)
        if parsed.scheme and parsed.scheme not in ('s3', 'gs', 'file', ''):
            raise ModelValidationError(f"Unsupported scheme in model path: {parsed.scheme}")

    def _get_s3_client(self):
        """Get or create S3 client."""
        if self.s3_client is None:
            self.s3_client = boto3.client('s3')
        return self.s3_client

    def _load_trusted_manifest(self) -> dict:
        """
        Load the trusted model manifest containing checksums.
        
        The manifest should be stored separately from models and 
        ideally be signed. It maps model versions to their expected
        SHA-256 checksums.
        
        Example manifest format:
        {
            "models": {
                "model-v1.0.joblib": {
                    "sha256": "abc123...",
                    "version": "1.0",
                    "approved_by": "ml-team",
                    "approved_at": "2024-01-15T00:00:00Z"
                }
            }
        }
        """
        logger.info("Loading trusted model manifest from: %s", self.manifest_path)
        
        parsed = urlparse(self.manifest_path)
        
        if parsed.scheme == 's3':
            bucket = parsed.netloc
            key = parsed.path.lstrip('/')
            client = self._get_s3_client()
            response = client.get_object(Bucket=bucket, Key=key)
            manifest_data = response['Body'].read()
        elif parsed.scheme in ('', 'file'):
            manifest_file = parsed.path if parsed.scheme == 'file' else self.manifest_path
            with open(manifest_file, 'r') as f:
                manifest_data = f.read()
        else:
            raise ModelValidationError(f"Unsupported manifest location scheme: {parsed.scheme}")
        
        if isinstance(manifest_data, bytes):
            manifest_data = manifest_data.decode('utf-8')
        
        manifest = json.loads(manifest_data)
        
        if 'models' not in manifest:
            raise ModelValidationError("Invalid manifest format: missing 'models' key")
        
        logger.info("Loaded manifest with %d model entries", len(manifest['models']))
        return manifest

    def _compute_checksum(self, file_path: str) -> str:
        """Compute SHA-256 checksum of a file."""
        sha256 = hashlib.sha256()
        with open(file_path, 'rb') as f:
            for chunk in iter(lambda: f.read(8192), b''):
                sha256.update(chunk)
        return sha256.hexdigest()

    def _verify_integrity(self, file_path: str, expected_checksum: str, model_name: str):
        """
        Verify the integrity of a downloaded model file.
        
        This is NON-OPTIONAL. Skipping this check would allow:
        - Backdoored models to be loaded (model poisoning)
        - Arbitrary code execution via malicious pickle payloads
        - Data exfiltration through compromised model files
        """
        actual_checksum = self._compute_checksum(file_path)
        
        if actual_checksum != expected_checksum:
            # Delete the suspicious file immediately
            os.unlink(file_path)
            
            logger.critical(
                "MODEL INTEGRITY CHECK FAILED for '%s'! "
                "Expected checksum: %s, Got: %s. "
                "This may indicate a model poisoning attack. "
                "The file has been deleted.",
                model_name, expected_checksum, actual_checksum
            )
            raise ModelIntegrityError(
                f"Checksum mismatch for model '{model_name}'. "
                f"Expected: {expected_checksum}, Got: {actual_checksum}. "
                f"Possible model poisoning attack detected."
            )
        
        logger.info(
            "Integrity verification PASSED for model '%s' (SHA-256: %s)",
            model_name, actual_checksum
        )

    def _validate_file_extension(self, filename: str):
        """Only allow safe model formats."""
        ext = Path(filename).suffix.lower()
        
        if ext in self.DISALLOWED_EXTENSIONS:
            raise ModelValidationError(
                f"Model format '{ext}' is not allowed because it permits "
                f"arbitrary code execution during deserialization. "
                f"Use .joblib, .onnx, .safetensors, or .pmml instead. "
                f"File: {filename}"
            )
        
        if ext not in self.ALLOWED_EXTENSIONS:
            raise ModelValidationError(
                f"Unrecognized model format '{ext}'. "
                f"Allowed formats: {self.ALLOWED_EXTENSIONS}. "
                f"File: {filename}"
            )

    def _get_latest_version(self, manifest: dict) -> tuple:
        """Get the latest approved model version from the manifest."""
        models = manifest['models']
        
        if not models:
            raise ModelValidationError("No models found in manifest")
        
        # Sort by version to get latest
        latest_name = None
        latest_version = None
        
        for name, info in models.items():
            version = info.get('version', '0.0')
            if latest_version is None or self._compare_versions(version, latest_version) > 0:
                latest_version = version
                latest_name = name
        
        if latest_name is None:
            raise ModelValidationError("Could not determine latest model version")
        
        return latest_name, models[latest_name]

    @staticmethod
    def _compare_versions(v1: str, v2: str) -> int:
        """Simple version comparison."""
        parts1 = [int(x) for x in v1.split('.')]
        parts2 = [int(x) for x in v2.split('.')]
        
        for a, b in zip(parts1, parts2):
            if a > b:
                return 1
            if a < b:
                return -1
        
        return len(parts1) - len(parts2)

    def _download_from_s3(self, s3_path: str, local_path: str):
        """Download a file from S3."""
        parsed = urlparse(s3_path)
        bucket = parsed.netloc
        key = parsed.path.lstrip('/')
        
        client = self._get_s3_client()
        logger.info("Downloading model from s3://%s/%s", bucket, key)
        client.download_file(bucket, key, local_path)

    def _download_model(self, model_name: str) -> str:
        """Download model to local cache and return local path."""
        parsed = urlparse(self.model_path)
        
        # Construct the full model path
        if parsed.scheme == 's3':
            base_path = self.model_path.rstrip('/')
            full_s3_path = f"{base_path}/{model_name}"
            
            local_path = os.path.join(self.local_cache_dir, model_name)
            # Ensure we don't write outside cache dir
            real_cache = os.path.realpath(self.local_cache_dir)
            real_local = os.path.realpath(local_path)
            if not real_local.startswith(real_cache):
                raise ModelValidationError("Path traversal detected in model name")
            
            self._download_from_s3(full_s3_path, local_path)
            return local_path
        
        elif parsed.scheme in ('', 'file'):
            base_dir = parsed.path if parsed.scheme == 'file' else self.model_path
            local_path = os.path.join(base_dir, model_name)
            
            # Verify the resolved path is within the expected directory
            real_base = os.path.realpath(base_dir)
            real_path = os.path.realpath(local_path)
            if not real_path.startswith(real_base):
                raise ModelValidationError("Path traversal detected in model name")
            
            if not os.path.exists(local_path):
                raise FileNotFoundError(f"Model file not found: {local_path}")
            
            return local_path
        
        else:
            raise ModelValidationError(f"Unsupported storage scheme: {parsed.scheme}")

    def _safe_load_model(self, file_path: str):
        """
        Load model using the safest available method for the format.
        """
        ext = Path(file_path).suffix.lower()
        
        if ext == '.joblib':
            logger.info("Loading joblib model: %s", file_path)
            return joblib.load(file_path)
        
        elif ext == '.onnx':
            try:
                import onnxruntime as ort
                logger.info("Loading ONNX model: %s", file_path)
                return ort.InferenceSession(file_path)
            except ImportError:
                raise ImportError("onnxruntime is required to load .onnx models")
        
        elif ext == '.safetensors':
            try:
                from safetensors import safe_open
                logger.info("Loading safetensors model: %s", file_path)
                return safe_open(file_path, framework="pt")
            except ImportError:
                raise ImportError("safetensors package is required to load .safetensors models")
        
        elif ext == '.json':
            logger.info("Loading JSON model: %s", file_path)
            with open(file_path, 'r') as f:
                return json.load(f)
        
        elif ext == '.pmml':
            try:
                from pypmml import Model
                logger.info("Loading PMML model: %s", file_path)
                return Model.fromFile(file_path)
            except ImportError:
                raise ImportError("pypmml is required to load .pmml models")
        
        else:
            raise ModelValidationError(f"No safe loader available for format: {ext}")

    def load_latest_model(self):
        """
        Securely load the latest model version.
        
        Steps:
        1. Load trusted manifest with checksums
        2. Determine latest model version
        3. Validate file extension is safe
        4. Download model file
        5. Verify checksum against manifest
        6. Load model using safe deserialization
        """
        logger.info("=" * 60)
        logger.info("SECURE MODEL LOADING - Starting")
        logger.info("=" * 60)
        
        # Step 1: Load manifest
        manifest = self._load_trusted_manifest()
        
        # Step 2: Get latest version
        model_name, model_info = self._get_latest_version(manifest)
        expected_checksum = model_info.get('sha256')
        
        if not expected_checksum:
            raise ModelIntegrityError(
                f"No SHA-256 checksum found in manifest for model '{model_name}'. "
                f"Every model MUST have a checksum to prevent poisoning attacks."
            )
        
        logger.info(
            "Latest model: %s (version: %s, approved_by: %s)",
            model_name,
            model_info.get('version', 'unknown'),
            model_info.get('approved_by', 'unknown')
        )
        
        # Step 3: Validate extension
        self._validate_file_extension(model_name)
        
        # Step 4: Download
        local_path = self._download_model(model_name)
        
        # Step 5: Verify integrity (MANDATORY - prevents model poisoning)
        self._verify_integrity(local_path, expected_checksum, model_name)
        
        # Step 6: Safe deserialization
        model = self._safe_load_model(local_path)
        
        logger.info("=" * 60)
        logger.info("Model '%s' loaded successfully and securely", model_name)
        logger.info("=" * 60)
        
        return model, model_info


def main():
    """
    Production inference service startup.
    
    Required environment variables:
        MODEL_PATH: Base path to models (s3://bucket/prefix or local path)
        MODEL_MANIFEST_PATH: Path to trusted manifest with checksums
    
    Optional environment variables:
        MODEL_BUCKET: S3 bucket name
        MODEL_CACHE_DIR: Local cache directory (default: /tmp/models)
    """
    try:
        loader = SecureModelLoader()
        model, model_info = loader.load_latest_model()
        
        logger.info(
            "Inference service ready with model version %s",
            model_info.get('version', 'unknown')
        )
        
        return model
        
    except ModelIntegrityError as e:
        logger.critical("SECURITY ALERT - Model integrity failure: %s", e)
        raise SystemExit(1)
    except ModelValidationError as e:
        logger.error("Model validation failed: %s", e)
        raise SystemExit(1)
    except Exception as e:
        logger.error("Failed to load model: %s", e)
        raise SystemExit(1)


if __name__ == '__main__':
    model = main()